#include<bits/stdc++.h>
using namespace std;
long long a[2000010];
vector<long long> mp[2000010];
long long w[21][2000010];
long long res=0;
long long dfs(long long x,long long d)
{
    long long ans=a[x];
    for(long long i=0;i<=20;i++)
    {
        w[i][(d+a[x])&((1<<i)-1)]^=1<<i;
    }
    for(long long i=0;i<=20;i++)
    {
        ans^=w[i][d&((1<<i)-1)];
    }
    for(long long i:mp[x])
    {
        ans^=dfs(i,d+1);
    }
    for(long long i=0;i<=20;i++)
    {
        ans^=w[i][d&((1<<i)-1)];
    }
    res+=ans;
    return ans;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(long long i=2;i<=n;i++)
    {
        long long f;
        scanf("%lld",&f);
        mp[f].push_back(i);
    }
    dfs(1,0);
    printf("%lld",res);
    return 0;
}
